3-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPQGU1ZIGPnqVqRmuQMUjw466b2VaGahjqFCiw3=w203-h305-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPWO6bFRxrwpXbroL1vKlwTW26ToeV3klTH3pmO=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPX57vOlq-_5h016TU9AVuW_PTF7gOXRr38HcBW=w203-h135-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPXH5yI4PkRajE_bwMcIbE4IHgMbiU1uhePuYRA=w203-h304-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPdDZeV2s3Pmqf1S8Nk5RPBZAQIiFSmmRpN6nDO=w203-h135-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPe1C0YMxnb4e_vmOerheEWFvrpTFdueVSkQm2m=w203-h304-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPhjVx8U_1aP6uYcy06PmssP0sox6wst3KIG9hp=w203-h135-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPliwW4_x-vu3N2ha-PxBOlFvkCA0yH9CCexdJ_=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPoDPlOSLOJJgy-EV9-ttQ3IAOT0_ErsT1K2ajl=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPoKGKhn8cTzy1KSYz10RfYYUlIBPZFF6kedv14=w203-h304-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPrQe0X98i-f74V8nVzuXZq3mkhM6MU1eK_7J_E=w203-h120-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPtqtPkGhnD48BnFbh6ycZc1DeX1jFso17Ar2nI=w203-h270-k-no"}]'::jsonb, '{"Friday":["5 a.m.–10 p.m."],"Monday":["5 a.m.–10 p.m."],"Saturday":["5 a.m.–10 p.m."],"Sunday":["5 a.m.–10 p.m."],"Thursday":["5 a.m.–10 p.m."],"Tuesday":["5 a.m.–10 p.m."],"Wednesday":["5 a.m.–10 p.m."]}'::jsonb, '[{"Name":"Scott Katz","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocK2XCIbTsOyZZxrRnViomzES6sjWrgTOjg3h5fS5shQOWlBTA=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"I dropped in as an expat. who speaks little Vietnamese.  I was treated with incredible kindness by the manager and by all of the players.  I was loaned a racquet and patiently guided into games with players of matching skill.  I was even given a free banana. 😉","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1Ys3OXBbteRVCNvmXxKPa3jnRkrdI0vw3xg45lEl011XHcOCh0NPV-eR9lzqlziYuhv_-6W5trVGJhBGbD5W0UwWy8wtVrWawsZiterDMTZ6DfPi229t4UfGKAagjFce3BIkEZ3V5KGtfF=k-no"],"When":"2025-10-31"},{"Name":"Trung Hiếu Trần","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjXsW2lXswMFcpPp4rfKiraF740eIFivxpehqyuu9AHuHuKR5sh7=s120-c-rp-mo-br100","Rating":5,"Description":"I just had a wonderful experience at this pickleball court and would like to share some highlights!\n\nThe court attracts many talented athletes with impressive skills. The matches are very lively and competitive. I learned a lot from their playing style and felt inspired to improve my own skills.\n\nThe owner of the court is very friendly and enthusiastic. They are always ready to assist and advise players. Their enthusiasm truly creates a positive atmosphere and encourages everyone to participate.\n\nThis pickleball court is not only a place to play sports but also a place to connect with others. The community here is large and welcoming, providing opportunities to meet and make friends with those who share the same passion. The social events and activities are also very enjoyable and enriching.\n\nIn summary, if you are looking for a place to play pickleball, this court is an excellent choice. I will definitely be coming back frequently!","Images":null,"When":""},{"Name":"T Tran","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWjEMG2LE5GRMq16rkK4dnC722n8gfpcXraZIL36noluwRzKarb=s120-c-rp-mo-br100","Rating":5,"Description":"Very friendly welcoming staff and members of the facility. Whether you are newbie or skillful players. This club has capability to accommodate what you need. The courts are spacious, good parking. Convenient location, near airport, Con market and shopping center. We love it.","Images":null,"When":""},{"Name":"Toan Ng","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocLXU5Pdp4fXdja2lDnBDIWX7U6NugBDnpIOchoGaEeYc7FMYw=s120-c-rp-mo-br100","Rating":5,"Description":"The owner Tri is a nice guy and was very welcoming. The people there were super friendly and accommodating even though we barely spoke any Vietnamese and are from overseas. Would highly recommend this Pickleball club regardless of skill level.","Images":null,"When":""},{"Name":"Mark Nishiyama","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWJJetCvZKo9bKg46g4wMdk-N7KHCfilNH_WLZwjBHuA9a4rn9-3Q=s120-c-rp-mo-br100","Rating":5,"Description":"Very nice place to play open pickleball. Thank you 👍","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn0R45cZsH1K9WfyghsToC8GHn1zUn7bCJzE3SRVz1cMa3knLw28uaqjqRD0smfJv1fJmYTpots_I7FArzYeuVHQPAp3lcrBAuthOV_l6R6eXV5iyzcJ6CNgH-18cKUqDI7GxFYm=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn2sf8BZQ4SBOn1mHHvJnxaB15MCiryPo2UD8pMBjwa8ZrLXfSmasD58k1sf7-ViVFnu9GpT6fqCe8Jald5T80sUX8zgTNRWKkwBNWOphgXr0yYJ2lJtaMmZbQMTdUTBfNaJP1as=k-no"],"When":"2025-1-5"},{"Name":"phuc nguyen","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJKsanuGVbmhuAyMaL9hgd-7WSu3vyHuRn4z7cjNvBZK2qwuQ=s120-c-rp-mo-br100","Rating":1,"Description":"Sân không quản lý được lượng người đánh, đánh social bình chọn đăng ký đánh lên 2 sân mà hơn 20 người, thành viên trong nhóm social mà 1 ngày đẹp trời tự nhiên bị kích ra không lý do.","Images":null,"When":""},{"Name":"Tán Văn Hải","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVBZl4G7l4eQvOh2Sy_ZpF3lIY2YEF9Wbo9XaJRtnrGT2ULIi65Gw=s120-c-rp-mo-br100","Rating":5,"Description":"Sân Pickleball Thanh khê quá đỉnh lun, Sân thoáng mát, Mặt sân phẳng, bề mặt có độ bám phù hợp, vạch kẻ rõ ràng theo đúng chuẩn pickleball. Sân có hệ thống đèn chiếu sáng tốt, chơi buổi tối vẫn đảm bảo tầm nhìn rõ ràng. 10 đỉm ko có nhưng, mọi người nên đến trãi nghiệm nha...🫰😍","Images":["h