aFZLHdhcQw3sqr-q8fYpefwu9D7vYqs3tkkqfn2zX95qtBeTPufBoeE=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAHz6pAiCWM6SvnR4X_IsmR8K4skEJgjoBafYFspeIr5TxEr0EvFcUFuQQA1C6lAdDjvooVdX39unEokRZVQ81i62NxIFZGUtH-UCwV80SK5w7hy574Ztm3PsZCwyYRlUdQg3vXiyHh5HkU=w203-h182-k-no"}]'::jsonb, '{"Friday":["5 a.m.–10 p.m."],"Monday":["5 a.m.–10 p.m."],"Saturday":["5 a.m.–10 p.m."],"Sunday":["5 a.m.–10 p.m."],"Thursday":["5 a.m.–10 p.m."],"Tuesday":["5 a.m.–10 p.m."],"Wednesday":["5 a.m.–10 p.m."]}'::jsonb, '[{"Name":"Y Trần","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVCoLInt6iEtJktW9yEwtZrliFt6Wu5F__dgEdRY6pbUi4G0aLknQ=s120-c-rp-mo-ba5-br100","Rating":5,"Description":"Good","Images":null,"When":""},{"Name":"Nguyễn Văn Quang","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVnKCvornjVRa9dpQp3ojC2aOEll_qMRRXvubsZrBhNm3TtyyU=s120-c-rp-mo-ba3-br100","Rating":4,"Description":"ok","Images":null,"When":""},{"Name":"Ho Hoang Nam","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJihpy_uzJ77a8clJH9-F7aGbmr4s2rspOPeBovV4B5lyFo=s120-c-rp-mo-ba5-br100","Rating":5,"Description":"Cụm sân mới với nhiều dịch vụ tiêu chuẩn. Mặt sân asphalt hạn chế tối đa chấn thương, giá rẻ hơn so với sân cùng phân khúc. Recommended!!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1gsUKjGBQlVR1jvQB7WnWqg0Dob235OzvB2urNF1vnVse7_VXzsagD3YJqpy7DuLQ-8Nz1isqfCQXDy32EgNUPO9IlO-7XVr-d2TuXxyE49nLvC1g3E1QDVZLSvLTsrihlsLEIJixU1gA=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn2yk6Xr6djr4H7IkuiAqWUM-PV4aRaEu-ADPrcSL7yB-LfE2QG3s0VBliyN9NDU6L0GVRGiOeZTuyTnCm-oK8k2XtaGINEc9Z80ZPFpr7_En0oCuUJ0VRMQuDOYjZLe4S8OQgMM0CCPXmqH=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn2i29SQJFqgkw7WJVo_YgKbPL3zZcrRsnb_P_ymp2h6uc1jAox-JFGfmukeJsR5I-3yv2wXWk0M4tFa0EISAVrF6N84GNEtUfIKg6_7qRBvZYm5Le5E8WgKF4ODjCKwVbFrJp67bhSh1yaD=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3q_1Sbjvz7R_ldmorYlxF2V8EoJiouUpNUAyyCs89iYS-Cs9P4W27EZYzD-YhjvZ5po-h1R3cta6fbMGelNchinM3bowa736_J3Jwve7m9juS3Z9iUMYBeiSAuPeka0TFPChDYKCN2JikP=k-no"],"When":"2025-7-12"},{"Name":"Ngọc Nguyễn Thị Như","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWqcmYbRucjbvSLk4IKpKJNdpg6awfFLXDTz0eGDi1PTiN8FzQ=s120-c-rp-mo-br100","Rating":5,"Description":"Tìm được quả sân mà ưng nha mấy ní 🤩! Vị trí sát sông, gió thổi lồng lộng, hít một hơi là quên sạch deadline, áp lực, drama cuộc đời luôn 😆. Sân thì mới tinh khôi, dụng cụ đủ từ A tới Á, phòng tắm sạch bóng loáng. Đánh xong hẹn người iu ra bờ sông chill chill thì hết bài ✨. Nói chung là tui mê rồi đó, thôi mấy ní tự trải nghiệm rồi hiểu nha 🤭","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2ye3tH_0k1FOtuSCjiLXuuj0MLciQ8pHpjtFEIMlej0aXQ65H-XOgslsB1EWZSCyNyqmmSGJVebRZepOM39g7PCkYZAD2sXiDe2iQ_61B_CmGJ-n_0YjdPthTiSSGxAr0uZ1NlI_eiy0DG=k-no"],"When":"2025-8-18"},{"Name":"Thục Minh Nguyễn","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjU1rz2UYlc2KybWDDl2RjnznJMJ4275JRSicKkpELuESDN-ciOw=s120-c-rp-mo-br100","Rating":5,"Description":"Sân thoáng mát. Không chỉ sân đẹp, ở đây còn có dịch vụ đầy đủ, phòng tắm sạch chỗ nghỉ ngơi thuận tiện","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn00AaZbQqsNZw2ipxDRR63c1vY4ibXE551_aK_9At4sd7-ae9zUqcIJeLbjLoglZLYu4HRzjYVP5FDWlXQpoz4r-vG4qq0n4RwCuydWMD3H0Cy9Cczn-zvTBzn_00w4btsWmdy4JXjOt8c=k-no"],"When":"2025-8-18"},{"Name":"Ka Sa","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJtF6FpuzQZbKePgJtiNCPYXUYXis_8_9zskfj_sVdzx353mw=s120-c-rp-mo-br100","Rating":1,"Description":"Đất rộng nhưng thiết kế sân quá tệ, 3 sân sát nhau, đường biên 2 bên không có chắn, đánh bóng 2 sân cứ qua lại cực kì khó chịu, buổi trưa tới chiều thì nắng nóng kinh khủng.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn0L0z-FoFs4Q6dVjXiGG9CmhzNfeohXHl9lb78UpwxxFK9JveOwWf5-7HKvCpBC7qxUt6_oYEkBMvCaI2DAXUauK2wRrj9jUnunwxWaFxYByVd5KNNwy65uanbqc_zYuCtD_pE8u2xAqbwQ=k-no"],"When":"2025-7-22"},{"Name":"Thoahoapct Lưu","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKyFA-OjHmqgw9j83xy3Bq6hzraT3PQ26Sup3HCeHqUUi0xAA=s120-c-rp-mo-br100","Rating":4,"Description":"Sân 1,2 thì OK, các sân còn lại thì chật chội, nhà vệ sinh sạch sẽ,bàn  ghế ngồi quá OK, giá cả hợp lý","Images":null,"When":""},{"Name":"TRAN THUAN","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWg70YClz7_njop0coz5MDJLPvTk5QGAdZQGKhtkJd2pd021xM=s120-c-rp-mo-br100","Rating":5,"Description":"- Mặt sân asphalt  di chuyển êm ái, giảm tối đa chấn thương, tăng độ bám và đảm bảo độ nảy bóng ổn định.\n- Dịch vụ tốt.\n1 trải nghiệm rất tốt.","Images":null,"When":""}]'::jsonb, '{"Friday":{"4":0,"5":9,"6":9,"7":9,"8":18,"9":26,"10":35,"11":37,"12":43,"13":54,"14":83,"15":100,"16":100,"17":83,"18":83,"19":84,"20":73,"21":43},"Monday":{"4":0,"5":16,"6":11,"7":9,"8":5,"9":13,"10":16,"11":26,"12":30,"13":49,"14":73,"15":90,"16":83,"17":77,"18":73,"19":81,"20":71,"21":49},"Saturday":{"4":0,"5":20,"6":26,"7":30,"8":33,"9":45,"10":45,"11":37,"12":30,"13":39,"14":50,"15":58,"16":58,"17":56,"18":49,"19":45,"20":35,"21":32},"Sunday":{"4":0,"5":47,"6":62,"7":69,"8":71,"9":66,"10":54,"11":43,"12":33,"13":43,"14":64,"15":88,"16":88,"17":71,"18":50,"19":47,"20":37,"21":37},"Thursday":{"4":0,"5":33,"6":43,"7":41,"8":35,"9":32,"10":22,"11":16,"12":18,"13":22,"14":35,"15":52,"16":64,"17":67,"18":69,"19":67,"20":50,"21":33},"Tuesday":{"4":0,"5":24,"6":22,"7":18,"8":16,"9":22,"10":26,"11":37,"12":43,"13":41,"14":41,"15":37,"16":45,"17":69,"18":84,"19":92,"20":67,"21":41},"Wednesday":{"4":0,"5":9,"6":5,"7":13,"8":24,"9":37,"10":41,"11":32,"12":37,"13":47,"14":71,"15":86,"16":84,"17":83,"18":77,"19":69,"20":50,"21":41}}'::jsonb, '[{"id":"amenities","name":"Amenities","options":[{"name":"Washroom","enabled":true}]}]'::jsonb, ARRAY['Washroom']::text[]) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EX