h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPMPkwd2dPigsKzJKZ07ikkEk1uGm4G-a5LUh6e=w203-h152-k-no"}]'::jsonb, '{"Friday":["4 a.m.–10 p.m."],"Monday":["4 a.m.–10 p.m."],"Saturday":["4 a.m.–10 p.m."],"Sunday":["4 a.m.–10 p.m."],"Thursday":["4 a.m.–10 p.m."],"Tuesday":["4 a.m.–10 p.m."],"Wednesday":["4 a.m.–10 p.m."]}'::jsonb, '[{"Name":"medium_nice","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWFDYo77BGcOj1gVOxIdDtk4K7d8Tmgm8RwulDHbG7MSsWJSIje=s120-c-rp-mo-ba6-br100","Rating":5,"Description":"Pickleball Thanh Hà is a great spot for anyone looking to play in a well-maintained and dedicated space. The court is set up nicely, making it a solid choice for both casual players and those who take the game a bit more seriously. One cool touch is their stylish colorful-themed paddle courts.\n\nWith 7 courts they are the biggest in Hoi An. If you’re into pickleball and in the area, it’s definitely worth checking out. It’s a good place to get a game going and be part of the growing pickleball scene in Vietnam!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn13XANG4immUaAkOKpPsbxOYISWeOg7ndtrxyGZBXFCVuKm8B88m5cemeS0z4GbQ6BIbTVb31mQnF3sGNAwqwYh5GlL6QTVZ93boH2o6eEAgBG09izvPGYMnO6DZ17JBerzMSD59w=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn24cySsMXCz6aYcw9ziffRD2OporM7-BJpIOW9RSy0hCIIZv6zfnz4Le8nEsm_wsMUmrWaaIOHjYwAjKuB5kZCWymHVsKnZJXr9O-IcH1NYZQCsppG3uxlXLzDKgK7LjpqP3otiHA=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn17MVd2GS19eXLSNLGtJ2Ttf9WIod68jaXSmi2AI-w6MqV0afp2wnLb1E1mpNKMVcL8kfiO6rimQXLJlak_UPP9YYqhAnNxBkt6RwuQGada34MsJbqaFC_tlv66aIMhcaoDA9I-=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3ESuQ1kK4Yj4EPyxRR-365_cw-iuqZtm4vRgdRk5Dg8zjjst0NXNqHnVMwdBRfcaWSjsL971aSa5v15CTgwn1Tbs8UzqvqXzT2hPsVDv_HL39i53Y9ivw3H8A_K5Rl16bUMb-SkQ=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn24x8msvej8Dsrf1oSPyWeXGpbq5rRx1kUmht-FN2AQ4AQDlvNX3Si5c7hlluhx1Uyk0u7v4j98jnrGRu48R4COvlBMfjRwGdk7xe_wZdvvgoBK5bp_6HPOw0sg7ykziXOdrRk-=k-no"],"When":"2025-3-2"},{"Name":"Roryandjuliet Douglas","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWD3LCIfOn_X4PhraayQKoKYGcnNSxD0NW8M8qbt99EYXrUT5o=s120-c-rp-mo-ba4-br100","Rating":5,"Description":"Nice courts, good equipment 😊 Cost 180k for 2 people and hiring 2 racquets for the hour. Was very quiet at 7am when we started, got a bit busier by 8am","Images":null,"When":""},{"Name":"Mattea Käppeli","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKOG29jZpEFbRI1ELmoX5b8B27e_VL0MvCxu53CmCjDt1SnBw=s120-c-rp-mo-br100","Rating":5,"Description":"such a fun sport and easy to rent a court for an hour!","Images":null,"When":""},{"Name":"Jenny Heavey","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocK_aTXPU5facDhUqOPyhc3K7Fhh7UpBk2uj80ooTqSf4t68bQ=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"Great place to meet the local Pickleballers. We were welcomed to play on our holiday from Melbourne","Images":null,"When":""},{"Name":"Joe Lum","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWwD7Z8C9Rx5z_Kdv63Dea-QoTn6FLbdkh6xMtf9_fkswzsjjCivw=s120-c-rp-mo-br100","Rating":5,"Description":"I''m from the states and was looking for a drop-in Open Play, and just happened to come upon a \"morning crowd\" that gets there at 9:30am (about 8 of them).  They welcomed me in and we had some great competitive games for a couple of hours.  The manager at the front desk doesn''t speak english and thought I wanted an hourly rental.  Good thing one of the players was billingual and it was just 30K for a \"social club fee\" for two hours.  There are 5 courts from what I saw and I don''t know whether or not there''s an afternoon/evening crowd or not, but when I left at 11:30am, no one else was playing.  Water is cheap too.  I''d say it''s a hit or miss, but I was very happy with the games!","Images":null,"When":""},{"Name":"Nguyenquang Minh","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocK8k9Mmjwcmi7QAs6HsQ9Z7NcmQFroRRsmeGls1RPqMVd_i-eY=s120-c-rp-mo-ba2-br100","Rating":1,"Description":"Mình quên cái đai lưng ở đấy,điện cho chủ sân rất nhiều lần,nhưng cố tình trì hoãn.Mình ở HN,đến khi cho người quên qua lấy thì k nghe máy,nhân viên thì bảo k biết. Làm mất công bạn chạy từ Đà nẵng vào. Chán.","Images":null,"When":""},{"Name":"Tri Minh","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKbYpmbYarCnxFCRI4mhvRG2v_8UX0Cvb_xqoVSzCyzxcMf3A=s120-c-rp-mo-br100","Rating":5,"Description":"Sân pickleball thoáng mát nhất Hội An. Giá rẻ, nên đến đây để trải nghiệm.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2LR6l3igE0LfDjRnl7SSFGB1mxX1EFgoMza-UnzcRbmFR63yucuTrri35GrTbgjAJ8jLcGH5SIC8sZoYf5vkje81yNe8XYzAkoleXw5lWsDJHr6y3cxkKFcXHSx3zJUIeFZ8zq_g=k-no"],"When":"2025-4-3"},{"Name":"Thuong Tran","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjXVoxsSrbj4mDWvzKZm6oWiZ3Zauz2rsJIqANapp2XGapvlq5qD=s120-c-rp-mo-br100","Rating":5,"Description":"Sân chơi rất ok, sạch sẽ, dịch vụ tốt","Images":null,"When":""}]'::jsonb, '{"Friday":{"3":0,"4":20,"5":17,"6":25,"7":31,"8":48,"9":54,"10":60,"11":42,"12":31,"13":25,"14":28,"15":40,"16":40,"17":31,"18":25,"19":14,"20":11,"21":8},"Monday":{"3":0,"4":5,"5":11,"6":20,"7":40,"8":54,"9":60,"10":54,"11":37,"12":31,"13":37,"14":37,"15":42,"16":40,"17":42,"18":34,"19":40,"20":40,"21":48},"Saturday":{"3":0,"4":25,"5":20,"6":31,"7":42,"8":68,"9":88,"10":88,"11":100,"12":77,"13":68,"14":54,"15":54,"16":42,"17":40,"18":31,"19":37,"20":25,"21":22},"Sunday":{"3":0,"4":22,"5":31,"6":25,"7":40,"8":48,"9":62,"10":57,"11":42,"12":40,"13":40,"14":54,"15":54,"16":60,"17":45,"18":42,"19":34,"20":37,"21":28},"Thursday":{"3":0,"4":17,"5":14,"6":17,"7":20,"8":22,"9":25,"10":25,"11":22,"12":20,"13":31,"14":54,"15":65,"16":60,"17":51,"18":48,"19":37,"20":37,"21":34},"Tuesday":{"3":0,"4":17,"5":17,"6":22,"7":40,"8":51,"9":57,"10":45,"11":31,"12":20,"13":17,"14":28,"15":31,"16":42,"17":40,"18":45,"19":37,"20":31,"21":34},"Wednesday":{"3":