],"Saturday":["6 a.m.–10 p.m."],"Sunday":["6 a.m.–10 p.m."],"Thursday":["6 a.m.–10 p.m."],"Tuesday":["6 a.m.–10 p.m."],"Wednesday":["6 a.m.–10 p.m."]}'::jsonb, '[{"Name":"Gia Bảo Dương","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjUbecbVO-40S9ICSZXFsSZJfTrVJ3uXtw318BQE7nI4429fmac=s120-c-rp-mo-br100","Rating":5,"Description":"This place was very clean and beautiful. It was clear and well organized, which made it easy to play pic. I would recommed it for everyone.","Images":null,"When":""},{"Name":"Hin","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVEiqq6emDY0mG7tbcz_9m2JZSVIfBSEzyLx4MBPqTARuF1LFLh=s120-c-rp-mo-br100","Rating":5,"Description":"Sân ở đây ok, chủ sân thoải mái, ở đây có tổ chức sân social chơi rất vui vẻ, thân thiện","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1vgED4yS8K7nBv5dJah_sjr9IqbMqF8a0ia4jp4ya8s7uNFjXrgYpHDH-hseGsQe9zM6yzGkMRtZ9XwbfEAyhUojQKD5L_1uT01vTLfw_lK6dMnfGy1kykxcpig0VMTdAZ01LFc89VSsfI=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3CpUnMhdd0xz7saSh8E5mVVfDeAx3qKJXVWBFULtI0PScTLbYFOmE7mPY7T9AhO1EZLEo13rRxcbeQjeSqv9zgX5FFJnAD53X3f8kCxSnhgmkuoGniu4-TiJx_OsMRwfjUTiGIo-1B-y7r=k-no"],"When":"2026-1-31"},{"Name":"Hồng Hạnh Phạm","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKWaShki_9uAop3K2qKu376JfMekCId-kASN8UTw3LjvqgYHw=s120-c-rp-mo-br100","Rating":1,"Description":"Sân nóng và bí\nNhóm mình thấy trên app phí từ 120-160k tuỳ ngày và khung giờ\nNhưng đến trực tiếp sân Đánh từ 11-12h trưa phí 170k/giờ (theo lời chị quản lý sân là đã hết giá khuyến mãi). Thấy cũng có chút sai sai nhưng cũng thanh toán và đi về vì lần thứ nhất k có lần thứ 2 quay lại 🤣 Phí quá cao so vs chất lượng của sân\nKhông nên thử nhé!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2Yn_gSC9gj02KSl-QuIf-viHjsrZ0qJ6zoZKBUjDIQI6f4kg_xybYlpVrtBlIFR4J_ZkG6mM-Iynx4le_u6VQ2_tvcWv4bkit3YfSfFw9nq0GS9MuSGmhB-jafi-mvL6kKis1IBnzAzi2I=k-no"],"When":"2025-10-4"},{"Name":"Cơm Niêu Nhà Đỏ","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVHogF2sBqbcgxCj643fSw8Gh1S59e2wOAUwcxpn2znuT5XQ8v1=s120-c-rp-mo-br100","Rating":5,"Description":"Sân mới, mát mẻ, giá lại hạt dẻ. Chỗ để ô tô thoả mái nữa. Sẽ đến thường xuyên.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1lShWHhSsHNqEn5lM2gnsLk8kZuTAPchQ633aaMU2KwV-8fWF9h1VY8wrXjcK2onLUSHP9Snq0AkxraTq9lgzvYl5-MN7pQdp2f7UaucovWugO17IXX6L5tc1ZLOjkCXDghHMh6I6ZxuIk=k-no"],"When":"2026-2-19"},{"Name":"Từ Đức","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKtYC-vUdqMi_x-NzexyDGiZr8JQgzpZ5bEKuYboSXHdzn9-A=s120-c-rp-mo-br100","Rating":5,"Description":"Sân đánh khá tốt giá cả cũng khá rẻ so với những nơi khác, buổi chìu đánh xé vé gặp những tay to đánh rất tín , ae mún nhanh lên trình thì có thể ghé sân này thử sức nhé.","Images":null,"When":""},{"Name":"Huynh Le Hieu","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjW684Vssy6sH41DQGgQMU2gRMzNl7KjLsfDbLtBhskPjG51bOI5mA=s120-c-rp-mo-ba5-br100","Rating":1,"Description":"Giá trên app 120k/h, nhưng nhóm mình ko book qua app mà đến sân thì phải trả 170k/h, theo lời chị chủ sân là đã hết khuyến mãi???\nChơi giờ ban ngày sân bí và nóng, cũng ko có gì đặc biệt hơn các sân khác, không biết dựa vào đâu mà lấy giá như vậy.\nTrải nghiệm 1 lần, sẽ không có lần thứ 2 quay lại.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn0qm6IFjyVWOuDE7h2W2yH39ljTxrz4hY-crKZwr4Sss4dHplUlajUM2ACXXXO0mymdL687sQYmNfOrefN9PWNchD2pUxOcDeDH7OTGjBdmlQkNkN0WiNUCF8fgYvZg5kFMELpLiwiBfUbG=k-no"],"When":"2025-10-4"},{"Name":"Chi Y","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocI5zdSRWZYnq4NwizQ7i-pfc3XSz5O1UU2An66dturL4p9NGQ=s120-c-rp-mo-br100","Rating":5,"Description":"Sân thoáng rộng giá cả hợp lý sẽ quay lại đặt sân cố định","Images":null,"When":""},{"Name":"Khánh L","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJ7uNbgikzX5bQyXlCOTLTsNqgQge5roUiutRKUVS_FMJ6ulw=s120-c-rp-mo-br100","Rating":1,"Description":"Chủ sân tự ý pass sân không báo trước trong khi nhóm đã thuê sân theo tháng và thanh toán tiền đầy đủ","Images":null,"When":""}]'::jsonb, '{"Friday":{"5":0,"6":63,"7":73,"8":68,"9":73,"10":63,"11":68,"12":47,"13":52,"14":47,"15":52,"16":42,"17":31,"18":21,"19":26,"20":47,"21":57,"22":0},"Monday":{"5":0,"6":15,"7":21,"8":21,"9":26,"10":26,"11":31,"12":21,"13":15,"14":21,"15":26,"16":36,"17":31,"18":36,"19":31,"20":36,"21":47,"22":0},"Saturday":{"5":0,"6":31,"7":31,"8":42,"9":36,"10":31,"11":26,"12":26,"13":31,"14":52,"15":47,"16":36,"17":21,"18":21,"19":10,"20":10,"21":15,"22":0},"Sunday":{"5":0,"6":26,"7":26,"8":36,"9":63,"10":57,"11":73,"12":68,"13":68,"14":52,"15":68,"16":63,"17":42,"18":26,"19":21,"20":26,"21":31,"22":0},"Thursday":{"5":0,"6":31,"7":36,"8":42,"9":47,"10":63,"11":78,"12":73,"13":63,"14":73,"15":78,"16":100,"17":84,"18":73,"19":68,"20":52,"21":47,"22":0},"Tuesday":{"5":0,"6":52,"7":52,"8":47,"9":52,"10":57,"11":63,"12":57,"13":68,"14":68,"15":36,"16":31,"17":47,"18":52,"19":52,"20":42,"21":42,"22":0},"Wednesday":{"5":0,"6":36,"7":57,"8":42,"9":42,"10":42,"11":47,"12":42,"13":42,"14":42,"15":63,"16":89,"17":89,"18":89,"19":89,"20":89,"21":63,"22":0}}'::jsonb, NULL, ARRAY[]::text[]) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags;
