iew but the walls are too close and restrict shots!","Images":null,"When":""},{"Name":"Đạt Phan Phúc","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKLKaXuIZtRmV7lw0NzZRVkVo2gHyiXXtJRoNXgdNUoAmhclQ=s120-c-rp-mo-br100","Rating":5,"Description":"Không gian rộng rãi, view thật chill","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn3oLPJHBwr9f5hEtxSOVoErARZKlAq8zLXDNhonRtZxl5PwTVNtJB5M9mCxr3f7qE0Z4kdAAZWkJK122Ium7Uq6qa7QETU7q4HnjwBvCIn5TUhhlguIUOIRbcCWgfaXQQtQyrMi=k-no"],"When":"2024-10-29"},{"Name":"Quang Tùng Phạm","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWFeu9lO7iBYa3H7YveduXIb14UIiXuKcQ0cSwncjfC0-EI60yn=s120-c-rp-mo-br100","Rating":5,"Description":"Sân sạch đẹp, nhân viên và thầy nhiệt tình","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn3fF9wg4rlv_XWNC9-VweICfcFq7QAjBglx8cwEGHysjuh3vTOro0X20LCZPMkpkBlEx77qKt8xFA0R7M9VguZQWq09BJHqcrziGVtMuJdv8X-Z-KbOVNAYwEeVjVJbzAXzrtpF=k-no"],"When":"2024-10-29"},{"Name":"vu tran","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocLk5QSlaPC3sNXAGxbsr1IV-kZTtaKn9UpX6QU0IwknMEe00w=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"","Images":null,"When":""},{"Name":"Hoang Hai Nguyen (Hai architect)","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjU56BwCYJfaWMhIY7Z3RfPvhQMNIa8duoUSf4YJ4ysk09O8ymHzAA=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"","Images":null,"When":""},{"Name":"Phương Mai Trần","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocI-PvqEpKCCHAVZ19FUrwRX97JpAjzFs4G3zHt--m6MjkMCLtE=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"","Images":null,"When":""}]'::jsonb, '{}'::jsonb, NULL, ARRAY[]::text[]) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, thumbnail_url = EXCLUDE