lJt42LR=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPaeI95f51lIzu79gRavQnAIE3y_PO7fEAiy1kd=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPbiHHFtNPXYc73e1_ENTi7F0810--dPlhLhbAW=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPg3HQfl6nR4UqFHl_cBabeCWRkvWFmFoU-mN_h=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPnoteimFVJFT9oDvKwVl0NYzemFBgTvgPguipX=w203-h270-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPo5-4Q0CpxAMdYg0u541UWsMNNaHrdFfiu7d2C=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPsq4TKk8bRn2jqAEpUcrxv7MDcL0bw-nytCIIV=w203-h135-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipPt1OwRk7QVRTBtMWDxVZbWcDLvGImTclzdRBbE=w203-h270-k-no"}]'::jsonb, '{"Friday":["5:30 a.m.–9:30 p.m."],"Monday":["5:30 a.m.–9:30 p.m."],"Saturday":["5:30 a.m.–9:30 p.m."],"Sunday":["5:30 a.m.–9:30 p.m."],"Thursday":["5:30 a.m.–9:30 p.m."],"Tuesday":["5:30 a.m.–9:30 p.m."],"Wednesday":["5:30 a.m.–9:30 p.m."]}'::jsonb, '[{"Name":"Angel Trinidad","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjU71fvyIvbRt7AYWu2zIcdjYPqT26SWy-XdQMMwn6ioxLZ4f05b=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"Came here by myself around 530 PM which was perfect time for their open play. Everyone was very friendly and welcoming, they invited me to play with them and if they could keep score in English for me they did. I don’t speak any Vietnamese so it was very nice of them to still make me feel welcomed.\n\nSon who works there helped me at the front and let me rent a paddle. The courts are well maintained and very dry even in the rain. There is also water, other drinks and ice cream for sale. I am definitely coming back again!! Thanks Choi Pickleball Center for a super fun time!\n\nOpen play times are below. Three hours of play for fee of 30,000 at the time of this post!\n\n6:30 AM\n11:30 AM\n5:30 PM\n\nThey also had free WiFi which came in clutch for me to get a Grab back to my place!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn3ffylAXDdmeZUECqIbdUogt6Ic2FdwpRnWuhAhn3uL2HhzIvdAoxvi3fduy4_9ftY6DWlIOpYTqrF3rvH9c9HbE-W9mKrWxMdHlxBA0v531MKi9U_ZlwTIAkjN0uI89hZetWN_OaDq6uja=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn00s45QjPE007Lwm8nGyB30fGSBA5KMqOSMNXAdwmSQ6B80PkteHDSOl1AFBgqq4DLHk22K9tnFB1-kx3Dx34lS-AhWBlOrQL_Kp2rX2Onxm47oZdUHnSqtpaGl8OjOlsMfb-RIWafXjvNd=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn2wG8ZUm8Ijgktwt0-1fRTGcorX-FOyC3EWiiOvQckvc8AmKfwRMExttidD5hUnQblfErxpLxL6XDYat_u4gL4AJxb0CdZNX36gHzDqDy9I4XH0tAj0BeGY8mCkcNIuTYtVoD49fL1-upk2=k-no"],"When":"2026-1-7"},{"Name":"Elsie M","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJ36HPRE3rhgK_PuNkLX6Da0lSs_BJ4zIVsJopUAMAvFg3fIQ=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"I loved this place!! It was close to the hotel, very fun. We got the courts originally to play skinny singles but little by little others showed up and we got to play a lot of doubles. Right as we were leaving, open play was starting and a lot of people started coming. Definitely a great facility.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn0JsE1OhnbgqouMj3v76R61s0Ny2xPvtS-psr_HPDJjt9hVEDc7WbGdH_PYcJCpkIrief38FKBdvENfwf95PvBMvuz_TifUpD2TjBX5aKTL1K2C1FaOWz-QJ7iWCYO1nu6VGkEMat2WBOa5=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn0YdvVxdItBKyZtjj6EepwmV3cJC4Nt2iI3hgNtHbwEc4LKWv4XCQXUcnEaBa8CaOdcrjRpGrf0HGRrcU-PVzArGlg1mWjDQ_XuNprGL89VeDdCThZyYfT9sA4DkFcf-1kr711LvNatvzOW=k-no"],"When":"2025-9-18"},{"Name":"Jermaine Hankston","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjUQHFTFKInCqjohiXnifiDhRqsaX8jzfZ3wE7RZrQ32E-71rLM=s120-c-rp-mo-ba2-br100","Rating":1,"Description":"This was a deeply disturbing experience. The pickleball instructor was rude, disrespectful, and showed clear racial bias toward me and my family as Black patrons. What made the situation worse is that he attempted to film us and tried to get us to repeat words in Vietnamese that we later realized were racial slurs without telling us what we were saying. This behavior was completely inappropriate, offensive, and unacceptable. No one should ever be treated this way, and management needs to address this immediately to ensure this kind of conduct never happens again.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn0INk8eFAIQmrZwys6DywjAdM0c5ZHbkAaD6RtwMe_8Mx_achUES2RM6t9Au95aJWxQ08Kikj8QXnz1juXG20M8XLHgBSY_oVvmevplKpvmYQMt-4qINihMi54bMzFjN-7RNfmJmXXAD-AG=k-no"],"When":"2026-1-30"},{"Name":"Bradley Tyberg","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjXhQ-qtMXgfxncjgFNPLnhrK1OsrpyTlecbTccKV6Tc1YfTE-VA=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"Best pickleball court in Danang! Great facilities in a great location with cool bar/cafe!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2DIQxhXyrwKr4WxIgSNK1Asqv6-_U4ROZOHAQmeAAsvgFmUrLMGHVpLMWtZ23ccJo1jmUGvWpwaGD_t16hnFGk26acgDeONYqAOpdc6XFNhu14cUwcEjdYGcS2-q1nm2tWV-x7=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3d2O-sb_uLPDZZhTFiB_qN9xuP3-O-5JiGcxnw82Z7rwpekxxcUec9lh0C1VtKvNBI870helKbwW7eRaN9Wju-cevoGsel-hduauWaZLN8kPH8MSwzlBONzVMJdt5b4NmLIzT_=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3iLjSnrNW_U4tgmJBcxD4srn_38h6e8-jVBEWcdpqm5QvHjYqExQLuaBIrlJ8iYM-nY6h-zznBEsbElonbjAw6VZHeik0s8aL2BKSgW1-qngqEGTU6HWteDoYo9CVbbDDxhB7c=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn0E_c-TT3XYU8c6NCZEzjkX97_PpFmLo0WihfWNMgu7_pSC_r98e0hhiiZfX1HlarQ_7nfuiYWaRe8DrZl8fyj97VQZQX_CLZcnm8decYmi3PdLpyL_FGeppsRdX-FYf1eI01Z2=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn1CbRaiW72yfEErXHJirWk2a8jOQToLqWxpc1FHDQDTnrMHKs7Mdn5BZdjswCN9b7mhRMSAjStxWfe_xvm1EPw1CsyJ5MXL6o9-uaqNr1LuaGu-WZKNs1MdG_sHKGWH_K7KIRJptA=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn1HISfhNoDfKjdb3MLjv6mI9FDgoUiMKBOW_1F6y6Lh2L3xG12yL5FgVo7j0YncDUDil1SxDLWhDlFIzzsi-eWkpsZqf4C1kY7xEHXYob1lB6y5jiD9RhyZDPWI7e8pAExlIuRIhg=k-no"],"When":"2025-6-12"},{"Name":"Giang Bui Trong","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocLCGnqLXckfjdef7fcxJctEOxXS2kBkIE0EylxBtswQ06S1sA=s120-c-rp-mo-br100","Rating":5,"Description":"A 6-court indoor & outdoor complex is located in a prime location just half of mile from beach resorts, hotels and best golf courts.\n\nGood quality court foundations and proof tents plus clean restrooms , especially you guys have a spacious garden area chilling out with music and beers after enjoying games.\n\nThe most impressive points is the host enthusiasm and his team mates good services.","Images":null,"When":""},{"Name":"Nam Do","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWSPAw4fSzodQx2VeM2hvyWzv5YJoSBBRmFoGqqAaJEBbaNB2Xq=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"Very fun place to play pickleball. I highly recommend!","Images":null,"When":""},{"Name":"nam trương văn","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocIzjLYTFbQ6lyESSqn6K9Y3u0Y4KGDFORQ2gYCLj7ILvEKawg=s120-c-rp-mo-br100","Rating":5,"Description":"Place good, everyone friendly","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2-m_MXQGEQdWy9r9dapLAgTNUXX1SgxAUxP8kIhZO8sLvDuD9FsFj-toNMmVTM8ehpgIyw5s4CJffix_Y8McGQtxxHA05g7h4VsvRwU5LeJRI15Vp4GBfJcQzXmrif8k_gxcQGTIV6YvUJ=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn19T-0eBE0sQbhooiJa6WwyIo7rOuBPPwiQrLw91Rp0ECNw_2rPenYtcN5LeiEX-WtkjLw6eoA6uMVX_cy5BhBPgWL-M30qUOViUMebfJUtLwioBj0fkrnCdyeMUGf-iEUoaFoigImC_s_B=k-no"],"When":"2025-9-18"},{"Name":"Thuỳ Dung Nguyễn","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocLQa0dhoEINjS8sbUqtbKKZIjv3g55tsPjVQk_4NS_mg8XRDw=s120-c-rp-mo-br100","Rating":5,"Description":"Good experience","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn2tAgEE8txBntIehJWSNXvg9c4KfPRwP7ag2E-0_RqX_aHTAXCF0rpA9ql4MCHpo4HEmLWcrCRBrFqzF2OrhbKVVghFeFF4k4rAKyx4YUsETHS4T5LCzi_2P5