mage":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAGsLaraZf0eJyZ0EQYvhX7GHihlGKaDJcz-4N6Z7ZE5Px7iMqKm6Wc866wbBvGeBFtkZZ_3_KZfjYx7nkCUfTNJYz3Nt_m2Nr1tPc2FW2Y35fRnKrhDJERIDHF1-_KZ59O-hH-W69q9nqMD=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAHA3W0-y4WwcqDlz--zdCir1mU2emgOc5-GPY-lBAsG7Hnjet5lRsLTrfdylfC1HO-Q5dse4HvHdl58cyFtE3o7zVJ5y-d28rqnrAB5BsrBn38qzkuFshb2TRLX-sbVEraF4jja4WU7ErBu=w203-h152-k-no"}]'::jsonb, '{"Friday":["5 a.m.–10 p.m."],"Monday":["5 a.m.–10 p.m."],"Saturday":["5 a.m.–10 p.m."],"Sunday":["5 a.m.–10 p.m."],"Thursday":["5 a.m.–10 p.m."],"Tuesday":["5 a.m.–10 p.m."],"Wednesday":["5 a.m.–10 p.m."]}'::jsonb, '[{"Name":"Thi Phuong Nga Tran (Mèo)","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjXqj3YEr71AA_k49U0N_BN_OwpQu-O62O0R8J1cQc6n9kynmv3FvQ=s120-c-rp-mo-ba4-br100","Rating":5,"Description":"Sân Pick đạn thoải mái, có phục vụ nước, sữa chua, chị chủ thân thiện nhiệt tình!","Images":null,"When":""},{"Name":"THIEN QUANG","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjV62pTph-DOZyn-OA0wNoVYzUmC6AQSKtwM28L4U4Y_O4_4NqTQXg=s120-c-rp-mo-br100","Rating":5,"Description":"Sân pick sang xịn mịn, mn vui vẻ !","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1PY0jDKitLxFzHZSciTsmxHNqwOS99aybZ9_v35qkgJq9KXzoAQJOot-ueJEvsEFkvuErgM3ETCV3rfYyawhDq0Go6sDB7-cVGJJAiPqQOBwf3hoBH_9-PiwSc3QA2goksGieYFHPpoK-a=k-no"],"When":"2026-1-21"},{"Name":"Quan Le","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjUjGyFtpr3ugZH5lWXd5Xd7AQroSR2W30nogQAPyBtLLEnFeeqA=s120-c-rp-mo-br100","Rating":1,"Description":"Tôi và bạn bè đã có một trải nghiệm cực kỳ thất vọng tại sân pickleball này. Thái độ của chủ sân rất thiếu chuyên nghiệp, tỏ ra khó chịu và cáu gắt khi chúng tôi hỏi về thời gian đặt sân cũng như cơ sở vật chất.\n\nSân cực kỳ bẩn, rác chưa được dọn, nền sân có nhiều vết ố và thậm chí có chỗ còn trơn trượt nguy hiểm. Không gian thì nóng nực, không có hệ thống thông gió hay quạt mát đầy đủ, khiến việc chơi thể thao trở nên mệt mỏi và khó chịu.\n\nCơ sở vật chất đã cũ kỹ, xuống cấp trầm trọng, các vạch sân mờ, lưới thì rách, và không có khu vực nghỉ ngơi hay để đồ sạch sẽ. Nhà vệ sinh thì bẩn và có mùi, rõ ràng không được dọn dẹp thường xuyên – hoàn toàn không đảm bảo vệ sinh và an toàn cho người chơi.","Images":null,"When":""},{"Name":"Phúc Lê","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJU3K1z4K45XgES2f8lQ_TRUW82aZkGHqOKrsv4vFRLTBsGrw=s120-c-rp-mo-br100","Rating":5,"Description":"Sân đẹp, mát mẻ, chị chủ nhiệt tình, dễ thương","Images":null,"When":""},{"Name":"HA VO LE NGOC","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocITw6Zjcw1-F78mjJ5gjin6NSdLvv945kYzoCsxlQ6qfGTesA=s120-c-rp-mo-br100","Rating":5,"Description":"Anh chị chủ thân thiện, tuyệt vời.","Images":null,"When":""},{"Name":"Ta Huong","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKdLEtx1PkMa_CDL9tZDjQa_8i3KyYTuUoivvLJS07-wRg7hQ=s120-c-rp-mo-br100","Rating":5,"Description":"Bà chủ nhiệt tình","Images":null,"When":""},{"Name":"Pông OHelix","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKxfoeJ2GyFlcxruAeNUMFgjTSiOfHkuVZwSA3IJuoiXA6RLg=s120-c-rp-mo-br100","Rating":1,"Description":"nóng","Images":null,"When":""},{"Name":"Tran Hieu","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKKTTIm-pN7bRD5QHJUi7Ml4tDJcpd6uGTDPDy9EmpgHeR33w=s120-c-rp-mo-br100","Rating":1,"Description":"nóng, chủ sân thái độ tệ","Images":null,"When":""}]'::jsonb, '{"Friday":{"4":0,"5":44,"6":38,"7":38,"8":33,"9":61,"10":50,"11":50,"12":44,"13":33,"14":50,"15":50,"16":61,"17":83,"18":88,"19":100,"20":72,"21":72},"Monday":{"4":0,"5":50,"6":66,"7":72,"8":61,"9":55,"10":44,"11":55,"12":44,"13":44,"14":22,"15":16,"16":22,"17":33,"18":38,"19":77,"20":77,"21":100},"Saturday":{"4":0,"5":38,"6":27,"7":22,"8":33,"9":38,"10":61,"11":55,"12":61,"13":38,"14":22,"15":27,"16":50,"17":83,"18":100,"19":88,"20":77,"21":38},"Sunday":{"4":0,"5":55,"6":55,"7":50,"8":55,"9":61,"10"