ll,"When":""},{"Name":"Steve Laycock","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjV4jtoU31Qq_ryCd5_CBVkxeA5RmOHIaUF_L7RHcOeOd9vtu-pO=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"Really cool court - great value, always responsive on zalo, and it''s right next to the beach so it''s perfect for an after game swim. Best court in DN!!","Images":null,"When":""},{"Name":"Bri","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWWoEEv4MKYfox1T1-bykQA1h17Y5YadhOfw__Wujz_hxt08rM=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"Had a private session with coach Kiet. Amazing and patient coach. Highly recommend.","Images":null,"When":""},{"Name":"Andrey Andryushin","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocL2h1C1uSQqf5fpqxDMSa3EhzJu4zRq6VZxrVpt-ppqXtNXjw=s120-c-rp-mo-br100","Rating":5,"Description":"Nice court. Great quality of the surface and lighting.\nCoaches of the Golden Tennis Academy are also amazing. I practice with Sean, would easily recommend him to anyone who wants to become a better player","Images":null,"When":""},{"Name":"Diego Alvarez","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjW1HMOdNU52C4XkvJf44S30L4-eqISKRDCrTkb_MProBMMv6Qtk=s120-c-rp-mo-br100","Rating":5,"Description":"Nice court. Bookings well managed","Images":null,"When":""},{"Name":"William Boumeester","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocLDGf9eUw1M6jTwBIjcTWWeb6UiL-_ARLmrDQdt-kl310RIbg=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"I was visiting Da Nang for a couple of weeks and wanted to play tennis.  My hotel helped connect me to Roger. Roger is an excellent player and a great hitting partner. He was able to accommodate my schedule and we played mostly in the evenings when it was cooler. Roger was very kind and responsive to WhatsApp messages  He is one of the best net players I’ve hit with. He can return the ball to the same location consistently. Amazing! I will play him again when I return to Da Nang.  Highly recommended!!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn1IkQy75jdfbGB2sxSTf3iGlQOTle5M9fNoUPVvYhGdjAuBFLMA4NbZa3Wd1dd4jyCtarZ2DWUhTBQM7xeA_3i_x-kWbLTIlANUWleCjr0_lJQN7vnaHTPgPW_Vq3OyHzVePlk=k-no"],"When":"2023-7-8"},{"Name":"Dai Le","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocKgYjpOrax3JDvaC1pwwV_FJeEZRuEVTRvFewaQymCD3oT0nh8=s120-c-rp-mo-br100","Rating":5,"Description":"Nice court and good coachs. I would prefer for taking most of private lessons","Images":null,"When":""},{"Name":"Fanatic Fnatic","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjW7_w9cBOw99XgDc0v2Cq8cwhVBgLyxuhwxCZZWu7d4SZ15GHw=s120-c-rp-mo-br100","Rating":1,"Description":"Terrible smell, bad court condition","Images":null,"When":""}]'::jsonb, '{"Friday":{"4":0,"5":40,"6":50,"7":60,"8":70,"9":65,"10":65,"11":55,"12":35,"13":45,"14":50,"15":70,"16":60,"17":50,"18":50,"19":35,"20":30,"21":40},"Monday":{"4":0,"5":40,"6":55,"7":40,"8":40,"9":40,"10":45,"11":35,"12":25,"13":30,"14":50,"15":75,"16":70,"17":80,"18":85,"19":100,"20":90,"21":70},"Saturday":{"4":0,"5":25,"6":15,"7":20,"8":20,"9":30,"10":40,"11":60,"12":45,"13":40,"14":35,"15":50,"16":40,"17":45,"18":30,"19":30,"20":30,"21":35},"Sunday":{"4":0,"5":40,"6":30,"7":30,"8":40,"9":65,"10":50,"11":40,"12":30,"13":30,"14":45,"15":60,"16":70,"17":55,"18":60,"19":75,"20":100,"21":95},"Thursday":{"4":0,"5":35,"6":50,"7":25,"8":20,"9":25,"10":35,"11":35,"12":30,"13":35,"14":50,"15":65,"16":75,"17":65,"18":65,"19":60,"20":55,"21":45},"Tuesday":{"4":0,"5":60,"6":50,"7":35,"8":25,"9":25,"10":35,"11":40,"12":30,"13":35,"14":30,"15":55,"16":50,"17":65,"18":70,"19":70,"20":70,"21":65},"Wednesday":{"4":0,"5":50,"6":45,"7":30,"8":25,"9":15,"10":15,"11":20,"12":40,"13":50,"14":70,"15":85,"16":70,"17":45,"18":40,"19":55,"20":75,"21":60}}'::jsonb, '[{"id":"service_options","name":"Service options","options":[{"name":"Onsite services","enabled":true}]},{"id":"accessibility","name":"Accessibility","options":[{"name":"Wh