-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipNifyGrnqhYJUSmZXENY46Lg5CCiFOKXnkoi0c=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipNyX3zPA54xQlZVQZ-qwpIzr3sgzBxQ45Fo_OA=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipO79tx2LQPG_uNPp9gcdW7EqT9oXRqgt9bOVZ8=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipOP7_Kh0KLU1pZXLt-ZNFJ943CN97dsU3ZISrs=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipOo63nyQB49wR3C_tbJwr32dcqSSwKxNQxqAOU=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipP0qncUGER6B4Yg1whIRXzzMAhZdtK8nhurKD8=w203-h152-k-no"},{"title":"Photo","image":"https://lh3.googleusercontent.com/p/AF1QipP4t-vsOuPDue-TYhgtGboa6DpE0MNc42Fmjis=w203-h270-k-no"}]'::jsonb, '{"Friday":["5 a.m.–10 p.m."],"Monday":["5 a.m.–10 p.m."],"Saturday":["5 a.m.–10 p.m."],"Sunday":["5 a.m.–10 p.m."],"Thursday":["5 a.m.–10 p.m."],"Tuesday":["5 a.m.–10 p.m."],"Wednesday":["5 a.m.–10 p.m."]}'::jsonb, '[{"Name":"gctseng gmail","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocI-WhsoVo0LLDbC7BFpYsE-JsTmd4wUwfNmZe6PfX0yRaNvEyok=s120-c-rp-mo-ba3-br100","Rating":5,"Description":"[Note: call ahead if you plan to go very early (like before 8:15AM). We were there at 5AM the first time we went and luckily one of the “regulars” were there playing and helped turned on the lights for our court before staff arrived.  The second time we went we were there at 8AM and by then I knew where the light switches were, haha.]\n\nPoon Poon Pickleball is like a 7-8min walk from Little Riverside Hoi An hotel (see my other review).  I was able to convince my spouse to play every single day we were in Hoi An.  Yes, she indulged me as we had to wake up extra early to ensure we had time to play, return to the hotel to eat breakfast before starting our tours and activities for the day.\n\nRates are ₫150.000/hr if you’re not a member (not sure what membership requires) and ₫140.000/hr for members. They’re kind of inconsistent in charging because the 1st time we visited we were charged ₫150k and then the second time we visited we were only charged ₫70k (for 1/2 hour).  Regardless, the staff was very nice.\n\nNice, clean courts with good baseline spacing.  They provide indoor balls (not sure about whether they provide paddles), but probably should use outdoor balls based on the surface of the courts.\n\nOverall, I’d be very happy staying at the same hotel we were in and coming here every morning.\n\n(Nobody’s asking, but yes I let her win a few games so she’d play more… .)","Images":null,"When":""},{"Name":"Ed Cobb (Double Shot)","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVzOkQgUMh13m6rTDH2oddeoW7CERz707_U2_wNVUNIle-cUyOVrg=s120-c-rp-mo-ba4-br100","Rating":5,"Description":"My first time playing pickleball. Nice courts and facilities. Great night. Very hot night so I was sweating a lot.","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn3029rN5_uMH2TWW9ZMDcFMMSBC25pUFFCoUk0F_VsBphjVO4c-W-nA4gT9zqktiuu5pAPRxLNTfaNFT2dN3ZzixSHTndyR39qwKDz9HaUgH4AvcPRgTL6UOaiKZBWoVp2E_fAQYX-EoRAH=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn3LzPxZD3GoDXOH_pxe9G6I9eS39jnNFAMQx9WrIz7BgXwiVwtpWdQ-67idQ6z-DEdNm7HY4UMNkuepzV8KTMfCBAKMbE0HnloaxvD1e_6vaHpl7j9rSlC-pspRkJOJT5veyfWmGfXKXjhq=k-no"],"When":"2025-8-13"},{"Name":"CWWSIM","ProfilePicture":"https://lh3.googleusercontent.com/a/ACg8ocJYD6mBqSK-p27z2oGH46RHX6htOelRKUqRN4X9GSpcptm8kg=s120-c-rp-mo-ba6-br100","Rating":5,"Description":"Great courts and such a fun place to be playing pickleball at! Nguyen was super helpful and friendly, would love to be back!","Images":["https://lh3.googleusercontent.com/grass-cs/ANxoTn3eNk0_8W8aQsIEIu0ZLeFW5Dj55iQB6wrvOebJ_aQDBE9QeMoJ243271Wjs2EY-xsBoHyN7QDY2o7CbUHmDqbiFpipxTpNmBn9U7fnzUot5j25PAdFR_f3WOp9HEyJQUPGdkwo=k-no","https://lh3.googleusercontent.com/grass-cs/ANxoTn25Gxc2OJmcX3gDfSDpmHr2UBy6BYOe1TiufDcR6A8tB7E_DD7tF4SwxszwyusM3X1S_UFKPZa8_o-s13NQ-Y-Md2yVCMriW_d9sF0NisAU1S2FuL94zhxEeKQtzrykio5aIKAC=k-no"],"When":"2024-10-30"},{"Name":"Sammy Blivaiss","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjVu0258bJvpiDScQ_kXYUAvy7oc9zKOdhAPlpMpzGwZmvMnq5A=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"What a gem to come across in Hoi An!\nWe heard the dinking down an alley and decided to walk on by and was amazed to see how many people are playing Pickleball. The next morning we returned to play!\nHighly recommend - paddle and ball are available for rent too!","Images":null,"When":""},{"Name":"Timothy Chan","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjWNk573UmAvgFs5NtXkqyzSo5AkLfOQAF7NK1gzbEeXd1Me-o5q=s120-c-rp-mo-ba4-br100","Rating":5,"Description":"Not a real review, just a helper for anyone looking for the courts: the map currently shows it on the north side of a small inlet (not the main river). It''s actually on the south side of the inlet. The courts themselves look in great condition.","Images":null,"When":""},{"Name":"Kai Tran","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjW-Egnf6We0F-VSZTrm46TUm8vsGYomjGghhjmiu3K9urzPDXDu=s120-c-rp-mo-br100","Rating":5,"Description":"Newly built with reasonable rent fee, racquet for rent is also available. Highly recommend for tourist who want to have sport activity.\nP/s: reservation in advance for suggestion! Their yards mostly full in evening time","Images":null,"When":""},{"Name":"Sam","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjUdockrjjJCRLokKRiwDhV-tSVSPUlkQpL3NFeyNSHuLf4Twmw=s120-c-rp-mo-ba2-br100","Rating":5,"Description":"Great place, clean field, good rental equipment and fair price.","Images":null,"When":""},{"Name":"Radi","ProfilePicture":"https://lh3.googleusercontent.com/a-/ALV-UjXRYr8o2p64GClcDUQ9VbrLZD_7wRWIvGIrIS4lX7ooRsEXsPTj5A=s120-c-rp-mo-ba5-br100","Rating":1,"Description":"They charged us extra money for being foreigners. First time this has ever happened. Charged us almost 3 times the normal amount for absolutely made up reasons.","Images":null,"When":""}]'::jsonb, '{"Friday":{"4":0,"5":45,"6":54,"7":51,"8":59,"9":81,"10":97,"11":94,"12":81,"13":83,"14":75,"15":72,"16":56,"17":43,"18":35,"19":29,"20":32,"21":32},"Monday":{"4":0,"5":35,"6":54,"7":72,"8":75,"9":64,"10":43,"11":35,"12":32,"13":51,"14":62,"15":62,"16":67,"17":70,"18":62,"19":54,"20":45,"21":37},"Saturday":{"4":0,"5":35,"6":54,"7":59,"8":56,"9":62,"10":67,"11":59,"12":40,"13":37,"14":54,"15":89,"16":100,"17":94,"18":54,"19":37,"20":35,"21":43},"Sunday":{"4":0,"5":29,"6":37,"7":45,"8":54,"9":48,"10":59,"11":51,"12":54,"13":56,"14":72,"15":72,"16":75,"17":64,"18":56,"19":43,"20":32,"21":24},"Thursday":{"4":0,"5":32,"6":54,"7":51,"8":62,"9":54,"10":51,"11":37,"12":35,"13":45,"14":70,"15":86,"16":94,"17":86,"18":81,"19":75,"20":75,"21":62},"Tuesday":{"4":0,"5":37,"6":54,"7":72,"8":72,"9":72,"10":72,"11":59,"12":43,"13":43,"14":43,"15":48,"16":59,"17":64,"18":70,"19":51,"20":35,"21":32},"Wednesday":{"4":0,"5":40,"6":45,"7":51,"8":48,"9":51,"10":48,"11":40,"12":29,"13":29,"14":35,"15":54,"16":59,"17":59,"18":54,"19":51,"20":62,"21":54}}'::jsonb, '[{"id":"service_options","name":"Service options","options":[{"name":"Onsite services","enabled":true}]},{"id":"accessibility","name":"Accessibility","options":[{"name":"Wheelchair-accessible parking lot","enabled":true}]}]'::jsonb, ARRAY['Onsite services', 'Wheelchair-accessible parking lot']::text[]) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.po